    ConsgMainComponent.prototype.chgPortDischarge = function (check) {
        if (check != null) {
            this.destcity = this.commoncities.filter(function (list) { return list.CITY_CODE === check; })[0].CITY_CODE;
        }
        else {
            this.destcity = null;
        }
    };
    //Invoice
    ConsgMainComponent.prototype.changeCurrency = function (check) {
        if (check != null) {
            if (check.split('|')[0] == 'CR115') {
                this.currencyrate = "1.00";
                this.inrrate = "1.00";
            }
            else {
                this.currencyrate = check.split('|')[2];
                this.inrrate = check.split('|')[3];
            }
        }
        else {
            this.currencyrate = "";
            this.inrrate = "";
        }
        this.calculateFOBMarket();
    };
    ConsgMainComponent.prototype.changeIncoterm = function (check) {
        if (check != null) {
            this.incoterm = check;
            this.frtchrgs = (this.incoterm == 'FOB' || this.incoterm == 'C&I') ? '' : this.frtchrgs;
            this.insuramt = (this.incoterm == 'FOB' || this.incoterm == 'C&F') ? '' : this.insuramt;
        }
        else {
            this.frtchrgs = null;
            this.insuramt = null;
        }
        //frieght
        if (this.incoterm == 'FOB') {
            this.frieght = "CC";
        }
    };
    ConsgMainComponent.prototype.changefreight = function (check) {
        if (check != null) {
            if (check != "CC" && this.incoterm == "FOB") {
                var vrf = confirm("You selected Incoterm FOB and freight 'PP',It should be 'CC' ,Are you sure you want to freight as . " + check + "?");
                if (vrf == true) {
                    this.frieght = check;
                }
                else {
                    this.frieght = "CC";
                }
            }
            else {
                if (check == "CC" && this.incoterm != "FOB") {
                    var vr = confirm("You selected Incoterm " + this.incoterm + " and freight 'CC',It should be 'PP' ,Are you sure you want to freight as . " + check + "?");
                    if (vr == true) {
                        this.frieght = check;
                    }
                    else {
                        this.frieght = "PP";
                    }
                }
            }
        }
    };
    ConsgMainComponent.prototype.changeddInvoiceShipType = function (check) {
        this.typeshpnbill = check;
        this.invshiptype = "";
    };
    ConsgMainComponent.prototype.changerbInvoiceShipType = function (check) {
        this.invshiptype = check;
    };
    ConsgMainComponent.prototype.calculateFOBMarket = function () {
        var tmp, fob, mktvalue;
        if (this.currency != null) {
            if (this.currency.split('|')[0] == 'CR115') {
                fob = Math.abs(this.invamt) - (((this.insuramt != null) ? this.insuramt : 0) + ((this.frtchrgs != null) ? this.frtchrgs : 0));
            }
            else {
                tmp = (this.invamt - (((this.insuramt != null) ? this.insuramt : 0) + ((this.frtchrgs != null) ? this.frtchrgs : 0))) * this.inrrate;
                fob = tmp / this.currencyrate;
            }
            mktvalue = (fob * 1.10);
            this.fobinr = Math.round(fob * 100) / 100;
            this.itcfobinr = this.fobinr;
            this.marketval = Math.round(mktvalue * 100) / 100;
        }
    };
    //Document List
    ConsgMainComponent.prototype.changeDocumentList = function (check, rbtype) {
        var updateItem = this.documentlist.find(function (item) { return item.DOCCODE === check; });
        var rType = null, cType = null, ntype = null;
        if (rbtype == "R") {
            rType = 'R' + check;
            cType = null;
            ntype = null;
        }
        else if (rbtype == "C") {
            rType = null;
            cType = 'C' + check;
            ntype = null;
        }
        else if (rbtype == "N") {
            rType = null;
            cType = null;
            ntype = 'N' + check;
        }
        var index = this.documentlist.indexOf(updateItem);
        this.documentlist[index]["RECD"] = rType;
        this.documentlist[index]["CALL"] = cType;
        this.documentlist[index]["NA"] = ntype;
    };
    ConsgMainComponent.prototype.getDocumentValue = function () {
        this.docreceived = "";
        this.doccallfor = "";
        for (var _i = 0, _a = this.documentlist; _i < _a.length; _i++) {
            var doc = _a[_i];
            if (doc.RECD != null) {
                this.docreceived += doc.RECD.substring(1) + ',';
            }
            else if (doc.CALL != null) {
                this.doccallfor += doc.CALL.substring(1) + ',';
            } //else if (doc.NA != null) { console.log(doc.NA); }
        }
    };
