    ConsgMainComponent.prototype.addEditOrderDtls = function () {
        if (this.validateOrder()) {
            if (this._loginService.getLogin()[0].CMPCODE != "01") {
                if (!this.checkOrderExistInAddedList()) {
                    this.crudOrder((this.hdordernoid == "0") ? "A" : "E", this.hdordernoid, this.hdorderid, this.hdexptno, this.orderno, this.orderpiece, this.ordertypeofpiece, this.orderwarehouse, this.orderpackage, this.ordergrwt, this.ordervolume, this.ordernetwt, this.orderchblwt, this.orderitemdesc, (this.orderlsddt == null) ? "" : this.orderlsddt.formatted, this.orderreferenceno, this.orderfobval, this.ordercurrency, (this.orderdrndt == null) ? "" : this.orderdrndt.formatted, this.ordercneedept, this.ordercontainerno, this.ordericshscode, this.ordericshsdescription);
                }
            }
            else {
                this.crudOrder((this.hdordernoid == "0") ? "A" : "E", this.hdordernoid, this.hdorderid, this.hdexptno, this.orderno, this.orderpiece, this.ordertypeofpiece, this.orderwarehouse, this.orderpackage, this.ordergrwt, this.ordervolume, this.ordernetwt, this.orderchblwt, this.orderitemdesc, (this.orderlsddt == null) ? "" : this.orderlsddt.formatted, this.orderreferenceno, this.orderfobval, this.ordercurrency, (this.orderdrndt == null) ? "" : this.orderdrndt.formatted, this.ordercneedept, this.ordercontainerno, this.ordericshscode, this.ordericshsdescription);
            }
        }
    };
    ConsgMainComponent.prototype.checkOrderExistInAddedList = function () {
        var _this = this;
        var filterData = this.orderlist.filter(function (filterby) { return filterby.ORDERNO == _this.orderno && filterby.STYLENO == _this.orderreferenceno && filterby.REF_ASSORTI == _this.ordercneedept; });
        if (this.orderlist.length > 0) {
            if (this.hdordernoid == 0) {
                if (filterData.length > 0) {
                    this._toasterService.toast('warning', 'Alert', 'You can not add same order number again.');
                    return true;
                }
                else {
                    return false;
                }
            }
        }
        else {
            if (this.checkedigroup != '0') {
                var filterExist = this.orderexistnolist.filter(function (filterby) { return filterby.ORDERNO == _this.orderno && filterby.STYLENO == _this.orderreferenceno && filterby.REF_ASSORTI == _this.ordercneedept; });
                if (filterExist.length > 0) {
                    return false;
                }
                else {
                    this._toasterService.toast('warning', 'Alert', 'Order No does not exist in the list. You can not add manually');
                    return true;
                }
            }
        }
    };
    ConsgMainComponent.prototype.validateOrder = function () {
        if (Math.abs(this.grosswt) == 0) {
            this._toasterService.toast('error', 'Error', 'Gross  Wt. in Vessel/Port/Goods can not be Empty.');
            return false;
        }
        if (Math.abs(this.volume) == 0) {
            this._toasterService.toast('error', 'Error', 'Volume in  Vessel/Port/Goods can not be Empty.');
            return false;
        }
        if (this.orderno == "") {
            this._toasterService.toast('error', 'Error', 'Order No. can not be Empty.');
            return false;
        }
        else if (Math.abs(this.orderpiece) == 0) {
            this._toasterService.toast('error', 'Error', 'Pieces can not be Empty.');
            return false;
        }
        else if (Math.abs(this.ordergrwt) == 0 || this.ordergrwt == "") {
            this._toasterService.toast('error', 'Error', "Gross wt should not blank");
            return false;
        }
        else if (Math.abs(this.orderchblwt) == 0 || this.orderchblwt == "") {
            this._toasterService.toast('error', 'Error', "Chbl wt should not blank");
            return false;
        }
        else if (Math.abs(this.ordervolume) == 0 || this.ordervolume == "") {
            this._toasterService.toast('error', 'Error', "Volume should not blank");
            return false;
        }
        var TotalPcs = 0;
        TotalPcs = (Math.abs(this.orderpiece)) + (Math.abs(this.hdnoofpcs_total) - Math.abs(this.hdnoofpcs_edit));
        if (this.noofpieces == null) {
            this._toasterService.toast('error', 'Error', "Please enter Total No.of Pcs.");
            return false;
        }
        if (Math.abs(TotalPcs) > Math.abs(this.noofpieces)) {
            this._toasterService.toast('error', 'Error', "Sum of Pcs should be less then or equal to Total No.of Pcs (" + String(this.noofpieces) + ")");
            return false;
        }
        //let TotalGrwt : any = 0;
        this.TotalGrwt = (Math.abs(this.ordergrwt)) + (Math.abs(this.hdnoofgrwt_total) - Math.abs(this.hdnoofgrwt_edit));
        this.TotalGrwt = parseFloat(this.TotalGrwt).toFixed(2);
        if (Math.abs(this.TotalGrwt) > Math.abs(this.grosswt)) {
            this._toasterService.toast('error', 'Error', "Sum of Order GrWt should be less then or equal to Total Gr.Wt (" + String(this.grosswt) + ")");
            return false;
        }
        //let Totalcbm = 0;
        this.Totalcbm = (Math.abs(this.ordervolume)) + (Math.abs(this.hdcbm_total) - Math.abs(this.hdcbm_edit));
        if (Math.abs(this.Totalcbm) > Math.abs(this.volume)) {
            this._toasterService.toast('error', 'Error', "Sum of Order Volume (" + String(this.Totalcbm) + ")should be less then or equal to Total Volume (" + String(this.volume) + ")");
            return false;
        }
        return true;
    };
