            exptno: exptno,
            orderno: ordernoid,
            orderpiece: orderpiece,
            ordertypeofpiece: ordertypeofpiece,
            orderwarehouse: orderwarehouse,
            orderpackage: orderpackage,
            ordergrwt: ordergrwt,
