    ConsgMainComponent.prototype.onTypeChange = function (type) {
        if (type == 'E') {
            this.customclr = false;
            this.freightfrd = false;
        }
        else if (type == 'C' || type == 'F') {
            this.exwork = false;
        }
    };
    ConsgMainComponent.prototype.validatePort = function () {
        if (this.shprgrosswt == null) {
            this._toasterService.toast('error', 'Error', "Shipper Gross Weight can not be blank");
            return false;
        }
        if (this.grosswt == null) {
            this._toasterService.toast('error', 'Error', "Gross Weight can not be blank");
            return false;
        }
        if (this.netwt == null) {
            this._toasterService.toast('error', 'Error', "Net Weight can not be blank");
            return false;
        }
        if (eval(this.netwt) > eval(this.grosswt)) {
            this._toasterService.toast('error', 'Error', "Net Weight should be less than or equal to Gross Weight");
            return false;
        }
        if (this.volume == null) {
            this._toasterService.toast('error', 'Error', "Volume can not be blank");
            return false;
        }
        if (this.modetype == "AIR") {
            if (eval(this.modetype) == 0) {
                this._toasterService.toast('error', 'Error', "Gross Weight can not be blank");
                return false;
            }
            else if (eval(this.volume) > (eval(this.grosswt) * 0.25)) {
                this._toasterService.toast('error', 'Error', "Volume should not be greter than 25% of Gross wt.");
                return false;
            }
        }
        return true;
    };
    ConsgMainComponent.prototype.validateInvoice = function () {
        if (this.docrecdt == null) {
            this._toasterService.toast('error', 'Error', "Document Received Date can not be blank");
            return false;
        }
        if (this.expinvno == null) {
            this._toasterService.toast('error', 'Error', "Invoice No. can not be blank");
            return false;
        }
        if (this.exptinvdt == null) {
            this._toasterService.toast('error', 'Error', "Invoice Date can not be blank");
            return false;
        }
        if (this._dataService.DateFromAndToComparision_exp(this.exptinvdt.formatted, this.docrecdt.formatted) == false) {
            this._toasterService.toast('error', 'Error', "Invoice Date Should be less than or Equal to Doc. Recd Date.");
            return false;
        }
        if (this.invamt == null) {
            this._toasterService.toast('error', 'Error', "Invoice amount can not be blank");
            return false;
        }
        if (this.incoterm != null) {
            if ((this.incoterm == "CIF") || (this.incoterm == "C&I")) {
                if (this.insuramt == null) {
                    this._toasterService.toast('error', 'Error', "Insurance amount can not be blank");
                    return false;
                }
                else if (this.insuramt > (this.invamt * 10 / 100)) {
                    this._toasterService.toast('error', 'Error', "Insurance Amount should be less than 10% of Invoice Amount");
                    return false;
                }
            }
            if ((this.incoterm == "CIF") || (this.incoterm == "C&I")) {
                if (this.frtchrgs == null) {
                    this._toasterService.toast('error', 'Error', "Freight Charges can not be blank");
                    return false;
                }
                else if (this.frtchrgs > (this.invamt * 60 / 100)) {
                    this._toasterService.toast('error', 'Error', "Freight Charges should be less than 60% of Invoice Amount");
                    return false;
                }
            }
        }
        return true;
    };
    ConsgMainComponent.prototype.deleteConfirm = function (index, codeid, code, exptno) {
        var confirmDel = confirm("Do you want to confirm?");
        if (confirmDel) {
            this.deleteITC(index, codeid, code, exptno);
        }
    };
