                    _this.actualfltno = data.Table[0].ACTUALFLIGHTNO;
                    _this.actualfltdt = (data.Table[0].ACTUALFLIGHTDT) ? _this._dataService.stringdttoArry(data.Table[0].ACTUALFLIGHTDT) : null; //this._dataService.stringdttoArry(data.Table[0].ACTUALFLIGHTDT);
                    _this.mawbno = data.Table[0].AEROBILLNO;
