    PortEditComponent.prototype.validatePort = function () {
        if (this.shprgrosswt == null) {
            this._toasterService.toast('error', 'Error', "Shipper Gross Weight can not be blank");
            return false;
        }
        if (this.grosswt == null) {
            this._toasterService.toast('error', 'Error', "Gross Weight can not be blank");
            return false;
        }
        if (this.netwt == null) {
            this._toasterService.toast('error', 'Error', "Net Weight can not be blank");
            return false;
        }
        if (eval(this.netwt) > eval(this.grosswt)) {
            this._toasterService.toast('error', 'Error', "Net Weight should be less than or equal to Gross Weight");
            return false;
        }
        if (this.volume == null) {
            this._toasterService.toast('error', 'Error', "Volume can not be blank");
            return false;
        }
        if (this.modetype == "AIR") {
            if (eval(this.grosswt) == 0) {
                this._toasterService.toast('error', 'Error', "Gross Weight can not be blank");
                return false;
            }
            else if (eval(this.volume) > (eval(this.grosswt) * 0.25)) {
                this._toasterService.toast('error', 'Error', "Volume should not be greter than 25% of Gross wt.");
                return false;
            }
        }
        return true;
    };
    PortEditComponent.prototype.validate = function () {
        var _this = this;
        if (this.validatePort() == false) {
            return false;
        }
        var cartdate = "", prealertdate = "", airlinename = "", planflightno = "", planflightdate = "", actflightno = "", actflightdate = "", mawbno = "", mawbdate = "", mawbdest = "", mawbfrt = "", hawbno = "", hawbdate = "", direct = "", tranport1 = "", flightno1 = "", etd1 = "", eta1 = "", tranport2 = "", flightno2 = "", etd2 = "", eta2 = "", aerobillno = "", aerobilldt = "", housebillno = "", housebilldt = "", vsl_code = "", vsl_port = "";
        var agent = "";
        if (this.modetype == "AIR" || this.ISDIFFAIR == '2') {
            cartdate = (this.cartingdt != null) ? this.cartingdt.formatted : "";
            prealertdate = (this.prealertsentdt != null) ? this.prealertsentdt.formatted : "";
            airlinename = this.airlinename;
            planflightno = this.plannedfltno;
            planflightdate = (this.plannedfltdt != null) ? this.plannedfltdt.formatted : "";
            actflightno = this.actualfltno;
            actflightdate = (this.actualfltdt != null) ? this.actualfltdt.formatted : "";
            mawbno = this.mawbno;
            mawbdate = (this.mawbdt != null) ? this.mawbdt.formatted : "";
            mawbdest = (this.mawbdest != null) ? this.mawbdest : "";
            mawbfrt = this.mawbfreight;
            hawbno = this.houseawbno;
            hawbdate = (this.houseawbdt != null) ? this.houseawbdt.formatted : "";
            if (this.transtype == "Direct") {
                direct = 'yes';
                tranport1 = "";
                tranport2 = "";
                etd1 = "";
                etd2 = "";
                eta2 = "";
            }
            else {
                direct = 'no';
                tranport1 = (this.transportone != null) ? this.transportone : "";
                tranport2 = (this.transporttwo != null) ? this.transporttwo : "";
                etd1 = (this.etdonedt != null) ? this.etdonedt.formatted : "";
                etd2 = (this.etdtwodt != null) ? this.etdtwodt.formatted : "";
                eta2 = (this.etatwodt != null) ? this.etatwodt.formatted : "";
            }
            flightno1 = this.fltno1;
            eta1 = (this.etaonedt != null) ? this.etaonedt.formatted : "";
            flightno2 = this.fltno2;
            aerobillno = this.mawbno;
            aerobilldt = (this.mawbdt != null) ? this.mawbdt.formatted : "";
            housebillno = this.houseawbno;
            housebilldt = (this.houseawbdt != null) ? this.houseawbdt.formatted : "";
            vsl_code = "";
            vsl_port = "";
            agent = "";
            if (actflightdate != '' && mawbdate != '') {
                if (this._dataService.DateFromAndToComparision(mawbdate, actflightdate) == false) {
                    this._toasterService.toast("error", "Alert", "Actual Flight date should be greater than or equal to MAWB date");
                    return false;
                }
                if (this._dataService.DateFromAndToComparision_exp(actflightdate, this._dataService.getCurrentdate()) == false) {
                    this._toasterService.toast("error", "Alert", "Actual Flight date Should be Less than or Equal to Current Date [ " + this._dataService.getCurrentdate() + "]");
                    return false;
                }
            }
        }
        else {
            vsl_code = this.vessel.split("|")[0];
            vsl_port = this.vessel.split("|")[1];
            agent = (this.agent != null) ? this.agent : "";
        }
        if (this.ISDIFFAIR == '2') {
            vsl_code = this.vessel.split("|")[0];
            vsl_port = this.vessel.split("|")[1];
            agent = (this.agent != null) ? this.agent : "";
        }
        var expt_ldgport = this.loadingport;
        var expt_cartplace = this.cartingplace;
        var expt_pod = (this.podchrg != null) ? this.podchrg : "";
        var expt_it = (this.portit != null) ? this.portit : "";
        var expt_destcity = (this.destcity != null) ? this.destcity : "";
        var expt_destcountry = (this.destcity != null) ? this.destcity : "";
        var expt_grwtshipper = this.shprgrosswt;
        var expt_volumeshipper = this.shprvolume;
        var expt_grwt = this.grosswt;
        var expt_netwt = this.netwt;
        var expt_volume = this.volume;
        var expt_frt = this.frieght;
        var expt_chblwt = this.chblwt;
        var expt_remarks = this.goodsremark;
        var expt_noofpkgs = this.noofpkgs;
        var expt_typeofpkgs = (this.typeofpkgs != null) ? this.typeofpkgs : "";
        var expt_noofpcs = this.noofpcs;
        var expt_typeofpcs = (this.typeofpcs != null) ? this.typeofpcs : "";
        var fkterminalid = (this.loadingportterminal.split("|")[0] == undefined || this.loadingportterminal.split("|")[0] == "") ? "" : this.loadingportterminal.split("|")[0];
        if (fkterminalid == "undefined") {
            fkterminalid = "";
        }
        var _jsonFinal = {
            Exptno: this.exptno,
            PKID: this.pkid,
            Expt_Guid: this._loginService.getLogin()[0].GUID,
            Expt_Mode: this.modetype,
            Expt_Noofpkgs: expt_noofpkgs,
            Expt_Typeofpkgs: expt_typeofpkgs,
            Expt_Noofpcs: expt_noofpcs,
            Expt_Typeofpcs: expt_typeofpcs,
            Expt_Grwt: expt_grwt,
            Expt_Netwt: expt_netwt,
            Expt_Volume: expt_volume,
            Expt_Vslagent: agent,
            Vsl_Code: vsl_code,
            Vsl_Port: vsl_port,
            Expt_Pod: expt_pod,
            Expt_It: expt_it,
            Expt_Destcity: expt_destcity,
            Expt_Destcountry: expt_destcountry,
            Expt_Frt: expt_frt,
            Expt_Remarks: expt_remarks,
            Citycode: this._loginService.getLogin()[0].CITYCODE,
            Cmpcode: this._loginService.getLogin()[0].CMPCODE,
            Expt_Grwtshipper: expt_grwtshipper,
            Expt_Volumeshipper: expt_volumeshipper,
            Expt_Ldgport: expt_ldgport,
            Expt_Cartplace: expt_cartplace,
            Expt_Chblwt: expt_chblwt,
            Username: this._loginService.getLogin()[0].CMPID,
            Citycode1: this._loginService.getLogin()[0].CITYCODE1,
            Cartdate: cartdate,
            Prealertdate: prealertdate,
            Airlinename: airlinename,
            Planflightno: planflightno,
            Planflightdate: planflightdate,
            Actflightno: actflightno,
            Actflightdate: actflightdate,
            Mawbdest: mawbdest,
            Mawbfrt: mawbfrt,
            Tranport1: tranport1,
            Flightno1: flightno1,
            Etd1: etd1,
            Eta1: eta1,
            Tranport2: tranport2,
            Flightno2: flightno2,
            Etd2: etd2,
            Eta2: eta2,
            Mawbno: mawbno,
            Mawbdate: mawbdate,
            Hawbno: hawbno,
            Hawbdate: hawbdate,
            CmpId: this._loginService.getLogin()[0].CMPID,
            MakerIp: this._loginService.getLogin()[0].CMPID,
            FK_TERMINALID: fkterminalid,
            VGUID: this._loginService.getLogin()[0].GUID
        };
        this.disabledBtn.emit(true);
        this._loaderService.display(true);
        this._dataService.Common("Export/UpdatePort", _jsonFinal)
            .subscribe(function (data) {
            _this.disabledBtn.emit(false);
            _this._loaderService.display(false);
            _this.result.emit({ status: data.Table[0].STATUS, message: "Export Port/Goods details updated Successfully!." });
        }, function (error) {
            _this._toasterService.toast('error', 'Error', error.status + '<br/>' + error.statusText);
        });
    };
