    InvoiceEditComponent.prototype.changeCurrency = function (check) {
        if (check != null) {
            if (check.split('|')[0] == 'CR115') {
                this.currencyrate = "1.00";
                this.inrrate = "1.00";
            }
            else {
                this.currencyrate = check.split('|')[2];
                this.inrrate = check.split('|')[3];
            }
        }
        else {
            this.currencyrate = "";
            this.inrrate = "";
        }
        this.calculateFOBMarket();
    };
    InvoiceEditComponent.prototype.changeIncoterm = function (check) {
        if (check != null) {
            this.incoterm = check;
            this.frtchrgs = (this.incoterm == 'FOB' || this.incoterm == 'C&I') ? '' : this.frtchrgs;
            this.insuramt = (this.incoterm == 'FOB' || this.incoterm == 'C&F') ? '' : this.insuramt;
        }
        else {
            this.frtchrgs = null;
            this.insuramt = null;
        }
        if (this.incoterm == 'FOB') {
            this.frieght = "CC";
        }
    };
    InvoiceEditComponent.prototype.changeddInvoiceShipType = function (check) {
        this.typeshpnbill = check;
        this.invshiptype = "";
    };
    InvoiceEditComponent.prototype.changerbInvoiceShipType = function (check) {
        this.invshiptype = check;
    };
    InvoiceEditComponent.prototype.calculateFOBMarket = function () {
        var tmp, fob, mktvalue;
        if (this.currency.split('|')[0] == 'CR115') {
            fob = Math.abs(this.invamt) - (((this.insuramt != null) ? this.insuramt : 0) + ((this.frtchrgs != null) ? this.frtchrgs : 0));
        }
        else {
            tmp = (this.invamt - (((this.insuramt != null) ? this.insuramt : 0) + ((this.frtchrgs != null) ? this.frtchrgs : 0))) * this.inrrate;
            fob = tmp / this.currencyrate;
        }
        mktvalue = (fob * 1.10);
        this.fobinr = Math.round(fob * 100) / 100;
        this.marketval = Math.round(mktvalue * 100) / 100;
    };
    InvoiceEditComponent.prototype.validateInvoice = function () {
        if (this.docrecdt == null) {
            this._toasterService.toast('error', 'Error', "Document Received Date can not be blank");
            return false;
        }
        if (this.expinvno == null) {
            this._toasterService.toast('error', 'Error', "Invoice No. can not be blank");
            return false;
        }
        if (this.exptinvdt == null) {
            this._toasterService.toast('error', 'Error', "Invoice Date can not be blank");
            return false;
        }
        if (this._dataService.date2Comparison(this.exptinvdt.formatted, this.docrecdt.formatted) == false) {
            this._toasterService.toast('error', 'Error', "Invoice Date Should be less than or Equal to Doc. Recd Date.");
            return false;
        }
        if (this.invamt == null) {
            this._toasterService.toast('error', 'Error', "Invoice amount can not be blank");
            return false;
        }
        if (this.incoterm != null) {
            if ((this.incoterm == "CIF") || (this.incoterm == "C&I")) {
                if (this.insuramt == null) {
                    this._toasterService.toast('error', 'Error', "Insurance amount can not be blank");
                    return false;
                }
                else if (this.insuramt > (this.invamt * 10 / 100)) {
                    this._toasterService.toast('error', 'Error', "Insurance Amount should be less than 10% of Invoice Amount");
                    return false;
                }
            }
            if ((this.incoterm == "CIF") || (this.incoterm == "C&I")) {
                if (this.frtchrgs == null) {
                    this._toasterService.toast('error', 'Error', "Freight Charges can not be blank");
                    return false;
                }
                else if (this.frtchrgs > (this.invamt * 60 / 100)) {
                    this._toasterService.toast('error', 'Error', "Freight Charges should be less than 60% of Invoice Amount");
                    return false;
                }
            }
        }
        return true;
    };
