    MAWBEditComponent.prototype.changefunction = function () {
        var _this = this;
        var verifyData = null;
        console.log(this.type);
        this._loginService.verifyRights(236, '')
            .subscribe(function (data) {
            _this.hdRightsView = _this._loginService.checkVerify('View', data); //For verify user access
            _this.NetRights = _this._loginService.returnRights('View', data, _this._loginService.getLogin()[0].ROLETYPE);
            _this._loginService.verifyRights(264, '')
                .subscribe(function (returnData) {
                _this.NetRightsAdd = _this._loginService.returnRights('Modify', returnData, _this._loginService.getLogin()[0].ROLETYPE);
                if (_this.NetRightsAdd == false) {
                    _this.NetRightsAdd = _this._loginService.returnRights('Add', returnData, _this._loginService.getLogin()[0].ROLETYPE);
                }
                _this.hdNetRights = (_this.NetRightsAdd == true) ? true : false;
            });
            // this._loaderService.display(true);
            _this.Resetchildrcrdpageload();
            verifyData = data.Table;
            _this.setDropDownData(_this._sharedconsig.exportEditData.MAWBNO, _this._sharedconsig.exportEditData.EXPTNO);
            _this.setData(_this._sharedconsig.exportEditData.MAWBNO, _this._loginService.getLogin()[0].CMP_USERENCCODE, _this._sharedconsig.exportEditData.EXPTNO, _this._loginService.getLogin()[0].CMPID, _this._loginService.getLogin()[0].GUID);
        });
    };
