    MAWBEditComponent.prototype.changePayOnTariff = function (tarType) {
        if (tarType == 'Fsc') {
            this.TarFscRate = 0;
            this.TarFsc = 0;
        }
        else if (tarType == 'Irc') {
            this.TarIrcRate = 0;
            this.TarIrc = 0;
        }
        else if (tarType == 'Xray') {
            this.TarXrayRate = 0;
            this.TarXray = 0;
        }
        else if (tarType == 'BP') {
            this.TarBPRate = 0;
            this.TarBP = 0;
        }
        else if (tarType == 'DT') {
            this.TarTruckRate = 0;
            this.TarTruck = 0;
        }
        else if (tarType == 'Misc') {
            this.TarMcRate = 0;
            this.TarMc = 0;
        }
        else if (tarType == 'CTG') {
            this.TarCtgRate = 0;
            this.TarCtg = 0;
        }
        else if (tarType == 'THC') {
            this.TarThcRate = 0;
            this.TarThc = 0;
        }
        this.fnCalculate_Tar();
    };
