    CreateAutoJobComponent.prototype.fill = function (check) {
        this.rbexporter = check;
        if (check == 1) {
            if (this.hdshipper != "") {
                this.drpShipper = this.hdshipper;
            }
            else {
                this.drpShipper = null;
            }
        }
        else if (check == 2) {
            if (this.hdexpt_billto != "") {
                this.drpShipper = this.hdexpt_billto;
            }
            else {
                this.drpShipper = null;
            }
        }
        else if (check == 3) {
            if (this.hdmanufacturer != "") {
                this.drpShipper = this.hdmanufacturer;
            }
            else {
                this.drpShipper = null;
            }
        }
    };
    CreateAutoJobComponent.prototype.drpfill = function (drpShipper) {
        if (drpShipper != null || drpShipper != "") {
            if (this.rbexporter == 1) {
                this.txtshipper = this.exporters.filter(function (exporter) { return exporter.VALUEFIELD === drpShipper; })[0].TEXTFIELD;
                this.txtexpt_billto = this.exporters.filter(function (exporter) { return exporter.VALUEFIELD === drpShipper; })[0].TEXTFIELD;
                this.hdshipper = drpShipper;
                this.hdexpt_billto = drpShipper;
                this.rbexporter = 2;
            }
            else if (this.rbexporter == 2) {
                this.txtexpt_billto = this.exporters.filter(function (exporter) { return exporter.VALUEFIELD === drpShipper; })[0].TEXTFIELD;
                this.hdexpt_billto = drpShipper;
            }
            else if (this.rbexporter == 3) {
                this.txtmanufacturer = this.exporters.filter(function (exporter) { return exporter.VALUEFIELD === drpShipper; })[0].TEXTFIELD;
                this.hdmanufacturer = drpShipper;
            }
        }
    };
